def roofline_throughput(
    peak_tflops: float,        # H100: 989 TFLOPS BF16
    peak_bw_tbs: float,        # H100: 3.35 TB/s
    model_params_b: float,     # 70 (billion)
    batch_size: int,
) -> dict:
    bytes_per_param = 2        # BF16
    model_bytes = model_params_b * 1e9 * bytes_per_param
    flops_per_token = model_params_b * 1e9 * 2   # 2 FLOP per multiply-add

    arith_intensity = (flops_per_token * batch_size) / (model_bytes)
    ridge = (peak_tflops * 1e12) / (peak_bw_tbs * 1e12)

    if arith_intensity < ridge:
        bound = "memory-bandwidth"
        max_toks = (peak_bw_tbs * 1e12) / model_bytes   # per second
    else:
        bound = "compute"
        max_toks = (peak_tflops * 1e12) / (flops_per_token * batch_size) * batch_size

    return {"bound": bound, "max_tok_per_s": round(max_toks), "batch": batch_size}

for bs in [1, 4, 16, 64, 256]:
    print(roofline_throughput(989, 3.35, 70, bs))
